+import React, { useEffect, useState } from 'react';
+import './RoomSoundIndicators.css';
+
+const soundTypes = {
+  forge: {
+    icon: '⚒️',
+    animationClass: 'forge-impact',
+    description: 'Forge Impact',
+  },
+  scribe: {
+    icon: '🎵',
+    animationClass: 'scribe-notes',
+    description: 'Scribe Musical Notes',
+  },
+  healer: {
+    icon: '✨',
+    animationClass: 'healer-magic',
+    description: 'Healer Magic Circle',
+  },
+  sentinel: {
+    icon: '⚠️',
+    animationClass: 'sentinel-alert',
+    description: 'Sentinel Alert',
+  },
+};
+
+// props: sounds = [{ type: 'forge'|'scribe'|'healer'|'sentinel', id: string }]
+export default function RoomSoundIndicators({ sounds }) {
+  const [activeSounds, setActiveSounds] = useState([]);
+
+  useEffect(() => {
+    // Filter to valid sounds only
+    const filtered = sounds.filter(s => soundTypes[s.type]);
+    setActiveSounds(filtered);
+  }, [sounds]);
+
+  if (activeSounds.length === 0) return null;
+
+  return (
+    <div className="room-sound-indicators" aria-label="Ambient sound indicators">
+      {activeSounds.map(({ type, id }) => {
+        const { icon, animationClass, description } = soundTypes[type];
+        return (
+          <span
+            key={id}
+            className={`sound-icon ${animationClass}`}
+            role="img"
+            aria-label={description}
+            title={description}
+          >
+            {icon}
+          </span>
+        );
+      })}
+    </div>
+  );
+}
